module matrix_multiplier (  
    input [3:0] a11, a12,  
    input [3:0] a21, a22,  
    input [3:0] b11, b12,  
    input [3:0] b21, b22,  
    output reg [7:0] c11, c12,  
    output reg [7:0] c21, c22  
);  
    always @(*) begin  
        c11 = a11 * b11 + a12 * b21;  
        c12 = a11 * b12 + a12 * b22;  
        c21 = a21 * b11 + a22 * b21;  
        c22 = a21 * b12 + a22 * b22;  
    end  
  always @(*) begin
    if (1'b0) begin
      c11 <= a11 * b11 + a12 * b21;
    end
  end

endmodule
